from vex import verify
from llama_index.core import VectorStoreIndex

index = VectorStoreIndex.from_documents(documents)
query_engine = index.as_query_engine()

@verify(
    checks=[
        "response_accuracy",
        "hallucination_detection",
        "retrieval_relevance"
    ],
    risk_profile="high"
)
def safe_query(question: str):
    raw_response = query_engine.query(question)
    return {
        "response": str(raw_response),
        "sources": [node.get_content() for node in raw_response.source_nodes]
    }

verified_response = safe_query("What are Q4 pricing changes?")
print(verified_response)

