import { verify } from 'vex-sdk';
import { OpenAI, VectorStoreIndex } from 'llamaindex';

const index = await VectorStoreIndex.fromDocuments(documents);
const queryEngine = index.asQueryEngine();

const verifyChat = verify({
  checks: ['response_accuracy', 'safety_filtering', 'pii_protection'],
  riskProfile: 'high'
});

export const chatHandler = verifyChat(async (req, res) => {
  const { message, chatHistory } = req.body;

  const response = await queryEngine.query({
    query: message,
    chatHistory
  });

  return {
    response: response.toString(),
    sources: response.sourceNodes.map(n => n.text),
    verified: true
  };
});

// Usage: app.post('/chat', chatHandler);
